// Utility: Decode base64 safely
function decodeBase64(data) {
  if (!data) return "";
  const cleaned = data.replace(/-/g, '+').replace(/_/g, '/');
  const padded = cleaned + "=".repeat((4 - cleaned.length % 4) % 4);
  return Buffer.from(padded, "base64").toString("utf-8");
}

// Utility: Extract full plain text recursively from Gmail payload
function extractPlainText(payload) {
  if (!payload) return "";

  if (payload.mimeType === "text/plain" && payload.body?.data) {
    return decodeBase64(payload.body.data);
  }

  if (payload.parts && Array.isArray(payload.parts)) {
    for (const part of payload.parts) {
      const text = extractPlainText(part);
      if (text) return text;
    }
  }

  // Fallback
  if (payload.body?.data) {
    return decodeBase64(payload.body.data);
  }

  return "";
}

// === Keywords to match ===
const literalKeywords = [
  "guest post",
  "guest-post",
  "guestpost",
  "link exchange",
  "link building",
  "submit article",
  "write for us",
  "contribute",
  "contributing",
  "sponsored post",
  "paid link",
  "blog exchange",
  "link insertion",
  "guest posting",
  "backlink exchange"
];

const regexKeywords = [
  "insert.*link"
];

// === MAIN MATCH LOGIC ===
const inputItems = $("Pull thread").all();
const results = [];

for (const item of inputItems) {
  const message = item.json.messages?.[0] || item.json;
  if (!message) {
    results.push({ json: { guestPostMatch: false } });
    continue;
  }

  // Extract subject
  const headers = Object.fromEntries((message.payload?.headers || []).map(h => [h.name, h.value]));
  const subject = (headers["Subject"] || "").toLowerCase();

  // Extract full plain text body
  const bodyText = extractPlainText(message.payload).toLowerCase();

  // Combine subject + body
  const combinedText = subject + " " + bodyText;

  let matchedKeyword = null;
  // First try literal matches
  const isLiteralMatch = literalKeywords.some(keyword => {
    const pattern = new RegExp(`\\b${keyword.replace(/\s+/g, '\\s+')}\\b`, 'i');
    if (pattern.test(combinedText)) {
      matchedKeyword = keyword;
      return true;
    }
    return false;
  });
  // Then try regex patterns only if no literal match
  const isRegexMatch = !isLiteralMatch && regexKeywords.some(regex => {
    const pattern = new RegExp(regex, 'i');
    if (pattern.test(combinedText)) {
      matchedKeyword = regex;
      return true;
    }
    return false;
  });
  const isMatch = isLiteralMatch || isRegexMatch;
  results.push({
    json: {
      guestPostMatch: isMatch,
      matchedKeyword,
      matchedTextPreview: combinedText.slice(0, 500)
    }
  });
}
return results;

