function findPartWithMimeType(parts, type) {
  for (const part of parts) {
    if (part.mimeType === type && part.body?.data) {
      return part.body.data;
    } else if (part.parts) {
      const nested = findPartWithMimeType(part.parts, type);
      if (nested) return nested;
    }
  }
  return null;
}

return $input.all()
  .map(item => {
    const msgs = item.json.messages || [item.json];  // thread or single message

    return msgs.map(msg => {
      const parts = msg.payload?.parts || [];

      // Try decoding from most preferred to fallback
      const html = findPartWithMimeType(parts, 'text/html');
      const plain = findPartWithMimeType(parts, 'text/plain');
      const fallback = msg.payload?.body?.data;

      const bodyBase64 = html || plain || fallback || '';
      const decodedBody = bodyBase64
        ? Buffer.from(bodyBase64, 'base64').toString('utf8')
        : '[No content found]';

      return {
        json: {
          subject: msg.payload?.headers?.find(h => h.name === 'Subject')?.value || '',
          from: msg.payload?.headers?.find(h => h.name === 'From')?.value || '',
          body: decodedBody,
          threadId: msg.threadId,
          id: msg.id,
          date: msg.internalDate
        }
      };
    });
  })
  .flat();  // flatten nested message list

