  for (const re of markers) {
    const idx = bodyText.search(re);
    if (idx >= 0) { fwdStart = (fwdStart === -1) ? idx : Math.min(fwdStart, idx); }
  }

  const block = fwdStart >= 0 ? bodyText.slice(fwdStart) : "";

  // 3) Extract fields from the forwarded block if found
  let originalSenderEmail = "";
  let cleanSubject = (last.subject || "").replace(/^fwd:\s*/i, "").trim();

  if (block) {
    const fromLine = pick(block, /From:\s*(.+)/i);
    originalSenderEmail = emailOf(fromLine) || emailOf(block) || "";
    const subjLine = pick(block, /Subject:\s*(.+)/i);
    if (subjLine) cleanSubject = subjLine.replace(/^fwd:\s*/i, "").trim();
