  // 4) Who forwarded it (the visible "from" of the last message)
  const forwardedByEmail = emailOf(last.from) || "";

  // 5) Final detection flag
  const isForwarded =
    !!block ||
    /forwarded message/i.test(bodyText) ||
    /^fwd\s*:/i.test(last.subject || "");

  // 6) Attach results
  return {
    json: {
      ...last,
      isForwarded,
      originalSenderEmail,
      forwardedByEmail,
      cleanSubject
