    return parts[2].trim();
  }

  // Fallback: "Begin forwarded message:" then skip headers until first blank line
  const idx = text.search(/Begin forwarded message\s*:/i);
  if (idx >= 0) {
    const rest = text.slice(idx);
    const blank = rest.search(/\n\s*\n/); // first blank line after headers
    if (blank >= 0) return rest.slice(blank).trim();
  }

  // Fallback: try to find headers (From:/To:/Date:/Subject:) and then first blank line
  const headersRe = /From:.*\n(?:.*\n){0,6}?Subject:.*\n/i;
  const m = text.match(headersRe);
  if (m) {
    const after = text.slice((m.index || 0) + m[0].length);
    const blank = after.search(/\n\s*\n/);
    if (blank >= 0) return after.slice(blank).trim();
  }

  return ""; // nothing extracted
}

// Normalize to an array of plain JSONs
const msgs = Array.isArray(sourceItems)
  ? sourceItems.map(i => i && typeof i === "object" && "json" in i ? i.json : null).filter(Boolean)
  : [];
debug.push('Messages found: ' + msgs.length);

// Sort by Gmail internalDate if present
msgs.sort((a, b) => (parseInt(a.date || 0) - parseInt(b.date || 0)));

// De-duplicate by message id (fallback to body)
const seen = new Set();
const unique = msgs.filter(m => {
  const key = m.id || m.body || '';
  if (seen.has(key)) return false;
  seen.add(key);
  return true;
});

// Build normal formatted thread (fallback)
const formattedMessages = unique.map(m => {
  const from = m.from || '';
  const to = m.to || '';
  const subject = m.subject || '';
  const date = m.date ? new Date(parseInt(m.date)).toLocaleString('en-IN') : 'Unknown Date';
  const body = m.body || '[No body found]';
  return `From: ${from}\nTo: ${to}\nDate: ${date}\nSubject: ${subject}\n\n${body}\n\n---`;
});
const fullThreadText = formattedMessages.join('\n');

// Latest item
const last = unique.length ? unique[unique.length - 1] : {};

// If forwarded: build a special body that starts *below* the forwarded headers
let aiBody = fullThreadText;
if (last.isForwarded) {
  const lastBodyText = htmlToText(last.body);
  const forwardedOnly = extractForwardedContent(lastBodyText);
  if (forwardedOnly) {
    aiBody = forwardedOnly;
    debug.push('Forwarded content extracted length: ' + forwardedOnly.length);
  } else {
    debug.push('Forwarded markers found, but content extraction failed; falling back to full thread.');
  }
}

// Stop-reply heuristic (same as before)
const threadTextLower = (aiBody || fullThreadText).toLowerCase();
const stopReply =
  threadTextLower.includes('neha rana') ||
  threadTextLower.includes('looped in a senior') ||
  threadTextLower.includes('escalate');

return [
  {
    json: {
      threadSummary: aiBody || '',
      latestSubject: last?.cleanSubject || last?.subject || '',
      latestFrom: last?.originalSenderEmail || last?.from || '',
      isForwarded: !!last?.isForwarded,
      originalSenderEmail: last?.originalSenderEmail || '',
      forwardedByEmail: last?.forwardedByEmail || '',
      stopReply,
      debug,
      threadId: last?.threadId || ''
    }
  }
];

const plainText = $input.first().json.output.reply_body

if (!plainText) {
  return [
    {
      json: {
        html: `<div style="font-family: Arial, sans-serif; font-size: 14px; color: #333;">
                 <p><i>No reply generated.</i></p>
                 <br>
                 <p>Best regards,<br>ScaleupAlly Team</p>
               </div>`
      }
    }
  ];
}

// Convert line breaks to <p> tags and bold words between ****
const formatted = plainText
  .split('\n')
  .map(line => {
    // Bold the content between ****
    line = line.replace(/\*\*(.*?)\*\*/g, '<b>$1</b>'); // Matches text between ** and replaces it with <b></b> tags
    return `<p>${line.trim()}</p>`;
  })
  .join('');

// Check if signature already exists
const lowerText = plainText.toLowerCase();
const hasSignature = lowerText.includes("best regards") || lowerText.includes("scaleupally.io");

const signatureBlock = hasSignature
  ? ''  // skip if already present
  : `<p>Best regards,<br>ScaleupAlly Team</p>`;

const htmlFormatted = `
  <div style="font-family: Arial, sans-serif; font-size: 14px; color: #333;">
    ${formatted}
    ${signatureBlock}
  </div>
`;

return [
  {
    json: {
      html: htmlFormatted
    }
  }
];
